5	/// Top-level daemon configuration.
6	/// Loaded from $XDG_CONFIG_HOME/vibe-attack/config.yaml (D-13, D-14).
7	#[derive(Debug, Clone, Deserialize, Serialize)]
8	#[serde(deny_unknown_fields)]
9	pub struct Config {
10	    pub ptt: PttConfig,
11	    pub timing: TimingConfig,
12	    #[serde(default)]
13	    pub audio: AudioConfig,
14	    #[serde(default)]
15	    pub pipeline: PipelineConfig,
16	    #[serde(default)]
17	    pub vad: VadConfig,
18	    #[serde(default)]
19	    pub stt: SttConfig,
20	    #[serde(default)]
21	    pub wake: WakeConfig,
22	    #[serde(default)]
23	    pub macros: Vec<MacroConfig>,
24	}
