26	impl Config {
27	    /// Validate that every model file path referenced in the config actually exists on disk.
28	    ///
29	    /// Called at daemon startup so the user gets an actionable error immediately rather than
30	    /// a cryptic panic when the pipeline tries to load a missing file.
31	    pub fn validate_model_paths(&self) -> Result<()> {
32	        if self.stt.enabled {
33	            let model_path = self
34	                .stt
35	                .model_path
36	                .as_ref()
37	                .context("stt.enabled is true but stt.model_path is not set")?;
38	            ensure_file_exists(model_path, "stt.model_path")?;
39	        }
40	
41	        if self.wake.enabled {
42	            let required = [
43	                (self.wake.encoder.as_ref(), "wake.encoder"),
44	                (self.wake.decoder.as_ref(), "wake.decoder"),
45	                (self.wake.joiner.as_ref(), "wake.joiner"),
46	                (self.wake.tokens.as_ref(), "wake.tokens"),
47	                (self.wake.keywords.as_ref(), "wake.keywords"),
48	            ];
49	
50	            for (path, field) in required {
51	                let path = path.with_context(|| format!("{field} is required when wake.enabled is true"))?;
52	                ensure_file_exists(path, field)?;
53	            }
54	        }
55	
56	        Ok(())
57	    }
58	}
59	
60	fn ensure_file_exists(path: &PathBuf, field: &str) -> Result<()> {
61	    std::fs::metadata(path).with_context(|| {
62	        format!(
63	            "{field} points to a missing file: {}\n\
64	             Provide a valid local path (no downloads are performed automatically).",
65	            path.display()
66	        )
67	    })?;
68	    Ok(())
69	}
