253	/// A single key event within a macro.
254	/// dwell_ms/gap_ms override the global TimingConfig defaults when set (D-06).
255	#[derive(Debug, Clone, Deserialize, Serialize)]
256	#[serde(deny_unknown_fields)]
257	pub struct KeyAction {
258	    /// evdev key name string, e.g. "KEY_UP". Parsed to evdev::KeyCode at runtime.
259	    pub key: String,
260	    /// Override global dwell_ms for this key only.
261	    pub dwell_ms: Option<u64>,
262	    /// Override global gap_ms after this key only.
263	    pub gap_ms: Option<u64>,
264	}
