266	/// Return the XDG config file path (D-14), creating the config directory if needed.
267	/// Resolves to $XDG_CONFIG_HOME/vibe-attack/config.yaml (default: ~/.config/vibe-attack/config.yaml).
268	pub fn default_config_path() -> Result<PathBuf> {
269	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
270	    xdg.place_config_file("config.yaml")
271	        .context("Failed to create XDG config directory for vibe-attack")
272	}
273	
274	/// Load and deserialize config from the given path (or XDG default).
275	/// Returns Err with an actionable message on any parse or I/O failure.
276	pub fn load(path_override: Option<&std::path::Path>) -> Result<Config> {
277	    let path = match path_override {
278	        Some(p) => p.to_path_buf(),
279	        None => default_config_path()?,
280	    };
281	
282	    let file = std::fs::File::open(&path).with_context(|| {
283	        format!(
284	            "Config file not found: {}\n\
285	             Create it at that path. See config.example.yaml for the format.",
286	            path.display()
287	        )
288	    })?;
289	
290	    let config: Config = serde_yaml_ng::from_reader(file).with_context(|| {
291	        format!("Failed to parse config file: {}", path.display())
292	    })?;
293	
294	    Ok(config)
295	}
